def rel(p:Path)->str:
    try: return str(p.relative_to(ROOT)).replace('\\','/')
    except Exception: return str(p)
def backup(path:Path)->Path:
    BACKUP_DIR.mkdir(parents=True,exist_ok=True); target=BACKUP_DIR/(rel(path).replace('/','__')+f'.before_{PATCH_ID}')
    if path.exists() and not target.exists(): target.parent.mkdir(parents=True,exist_ok=True); shutil.copy2(path,target)
    return target
def write_file(path:str,text:str)->dict[str,Any]:
    p=ROOT/path; p.parent.mkdir(parents=True,exist_ok=True); existed=p.exists(); b=backup(p); old=p.read_text(encoding='utf-8',errors='ignore') if existed else ''; mutated=old!=text
    if mutated: p.write_text(text,encoding='utf-8')
    return {'path':path,'existed_before':existed,'mutated':mutated,'backup_path':str(b) if existed else None}
def append_once(path:str,text:str,marker:str)->dict[str,Any]:
    p=ROOT/path; p.parent.mkdir(parents=True,exist_ok=True); existed=p.exists(); old=p.read_text(encoding='utf-8',errors='ignore') if existed else ''; b=backup(p)
    if marker in old: return {'path':path,'existed_before':existed,'mutated':False,'backup_path':str(b) if existed else None}
    p.write_text(old+('' if not old or old.endswith('\n') else '\n')+text.rstrip()+'\n',encoding='utf-8')
    return {'path':path,'existed_before':existed,'mutated':True,'backup_path':str(b) if existed else None}
def replace_many(path:str,replacements:dict[str,str])->dict[str,Any]:
    p=ROOT/path; existed=p.exists(); old=p.read_text(encoding='utf-8',errors='ignore') if existed else ''; b=backup(p); new=old
    for src,dst in replacements.items(): new=new.replace(src,dst)
    if new!=old: p.write_text(new,encoding='utf-8')
    return {'path':path,'existed_before':existed,'mutated':new!=old,'backup_path':str(b) if existed else None}
def patch_state_file():
    p=ROOT/'src/tradebot/state.py'
    if not p.exists(): return None
    old=p.read_text(encoding='utf-8',errors='ignore'); b=backup(p)
    needed=[('last_reconcile_result','last_reconcile_result: str | None = None'),('startup_hygiene_snapshot','startup_hygiene_snapshot: dict | None = None')]
    if all(k in old for k,_ in needed): return {'path':'src/tradebot/state.py','existed_before':True,'mutated':False,'backup_path':str(b)}
    lines=old.splitlines(); insert_at=None; indent='    '
    for i,line in enumerate(lines):
        if 'last_order_event' in line or 'last_preflight' in line:
            insert_at=i+1; indent=line[:len(line)-len(line.lstrip())]
    if insert_at is None:
        for i,line in enumerate(lines):
            if line.startswith('class RuntimeState'): insert_at=i+1; break
